        if used >= k {
            // Only move normally
            if y + 1 < n {
                let new_cost = dist[x as usize][y as usize] + grid[x as usize][y as usize];
                if new_cost < dist[x as usize][y + 1 as usize] {
                    dist[x as usize][y + 1 as usize] = new_cost;
                    pq.push(State { cost: new_cost, x: x, y: y + 1, used: used });
